package genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.service.RationPolicyService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/hr/ration-policies") public class RationPolicyController { private final RationPolicyService service; public RationPolicyController(RationPolicyService service){this.service=service;} @GetMapping public List<RationPolicyResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public RationPolicyResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public RationPolicyResponse create(@RequestBody RationPolicyUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public RationPolicyResponse update(@PathVariable UUID id,@RequestBody RationPolicyUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
